/**
 * @param {number[]} landStartTime
 * @param {number[]} landDuration
 * @param {number[]} waterStartTime
 * @param {number[]} waterDuration
 * @return {number}
 */
var earliestFinishTime = function(landStartTime, landDuration, waterStartTime, waterDuration) {
    const m = landStartTime.length;
    const n = waterStartTime.length;

    let minl = Infinity;
    let minw = Infinity;
    let res = Infinity;

    for (let i = 0; i < m; i++) {
        minl = Math.min(minl, landStartTime[i] + landDuration[i]);
    }

    for (let j = 0; j < n; j++) {
        minw = Math.min(minw, waterStartTime[j] + waterDuration[j]);
        res = Math.min(res, Math.max(minl, waterStartTime[j]) + waterDuration[j]);
    }

    for (let i = 0; i < m; i++) {
        res = Math.min(res, Math.max(minw, landStartTime[i]) + landDuration[i]);
    }

    return res;
};
